// collectMethodsAllowed flags the routing context as having matched a
// route pattern with an unsupported method, and records the methods that
// are actually registered for that pattern's endpoints so they can be
// used to populate the Allow header on a 405 response.
func collectMethodsAllowed(rctx *Context, eps endpoints) {
	rctx.methodNotAllowed = true
	rctx.methodsAllowed = rctx.methodsAllowed[:0]
	for mt, ep := range eps {
		if mt == mALL || mt == mSTUB {
			continue
		}
		if ep == nil || ep.handler == nil {
			continue
		}
		rctx.methodsAllowed = append(rctx.methodsAllowed, mt)
	}
	sort.Slice(rctx.methodsAllowed, func(i, j int) bool {
		return rctx.methodsAllowed[i] < rctx.methodsAllowed[j]
	})
}

