// CORSOptions configures the middleware returned by CORS. See
// DefaultCORSOptions for sensible defaults.
type CORSOptions struct {
	// AllowOrigin is the value written to the Access-Control-Allow-Origin
	// header on every response. Defaults to "*".
	AllowOrigin string

	// AllowMethods is the fallback list of methods advertised via the
	// Access-Control-Allow-Methods header on a preflight response, used
	// when the request path can't be matched against the router.
	AllowMethods []string

	// AllowHeaders is the value written to the Access-Control-Allow-Headers
	// header on preflight responses.
	AllowHeaders []string

	// ExposeHeaders is the value written to the
	// Access-Control-Expose-Headers header on non-preflight responses.
	ExposeHeaders []string

	// MaxAge is the value, in seconds, written to the
	// Access-Control-Max-Age header on preflight responses. A zero value
	// omits the header.
	MaxAge int

	// AllowCredentials sets the Access-Control-Allow-Credentials header to
	// "true" when enabled.
	AllowCredentials bool
}

// DefaultCORSOptions returns CORSOptions with permissive, commonly-used
// defaults: any origin, the standard HTTP methods, a small set of common
// request headers, and a 1-hour preflight cache.
func DefaultCORSOptions() CORSOptions {
	return CORSOptions{
		AllowOrigin: "*",
		AllowMethods: []string{
			http.MethodGet, http.MethodPost, http.MethodPut,
			http.MethodPatch, http.MethodDelete, http.MethodHead, http.MethodOptions,
		},
		AllowHeaders: []string{"Accept", "Authorization", "Content-Type"},
		MaxAge:       3600,
	}
}

// corsProbeMethods is the set of methods probed, in a stable order, when
// detecting which methods are registered for a route's pattern.
var corsProbeMethods = []string{
	http.MethodConnect,
	http.MethodDelete,
	http.MethodGet,
	http.MethodHead,
	http.MethodOptions,
	http.MethodPatch,
	http.MethodPost,
	http.MethodPut,
	http.MethodTrace,
}

// CORS returns middleware that adds Cross-Origin Resource Sharing headers
// to responses, and automatically handles preflight OPTIONS requests. The
// Access-Control-Allow-Methods header on a preflight response is computed
// from the methods actually registered against the matched route, falling
// back to options.AllowMethods when no route can be matched.
func CORS(options CORSOptions) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			origin := options.AllowOrigin
			if origin == "" {
				origin = "*"
			}
			w.Header().Set("Access-Control-Allow-Origin", origin)
			if options.AllowCredentials {
				w.Header().Set("Access-Control-Allow-Credentials", "true")
			}
			if len(options.ExposeHeaders) > 0 {
				w.Header().Set("Access-Control-Expose-Headers", strings.Join(options.ExposeHeaders, ", "))
			}

			if r.Method == http.MethodOptions && r.Header.Get("Access-Control-Request-Method") != "" {
				methods := allowedMethodsForPath(r)
				if len(methods) == 0 {
					methods = options.AllowMethods
				}
				if len(methods) > 0 {
					w.Header().Set("Access-Control-Allow-Methods", strings.Join(methods, ", "))
				}
				if len(options.AllowHeaders) > 0 {
					w.Header().Set("Access-Control-Allow-Headers", strings.Join(options.AllowHeaders, ", "))
				}
				if options.MaxAge > 0 {
					w.Header().Set("Access-Control-Max-Age", strconv.Itoa(options.MaxAge))
				}
				w.WriteHeader(http.StatusNoContent)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

// allowedMethodsForPath detects, in stable order, which HTTP methods are
// registered against the route matching the request's path.
func allowedMethodsForPath(r *http.Request) []string {
	rctx := RouteContext(r.Context())
	if rctx == nil || rctx.Routes == nil {
		return nil
	}

	routePath := rctx.RoutePath
	if routePath == "" {
		if r.URL.RawPath != "" {
			routePath = r.URL.RawPath
		} else {
			routePath = r.URL.Path
		}
		if routePath == "" {
			routePath = "/"
		}
	}

	var methods []string
	for _, method := range corsProbeMethods {
		tctx := NewRouteContext()
		if rctx.Routes.Match(tctx, method, routePath) {
			methods = append(methods, method)
		}
	}
	return methods
}

