package smoke

import (
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
)

func TestCoreAllowHeader(t *testing.T) {
	r := chi.NewRouter()
	r.Get("/users", func(w http.ResponseWriter, r *http.Request) {})
	r.Head("/users", func(w http.ResponseWriter, r *http.Request) {})

	req := httptest.NewRequest(http.MethodPut, "/users", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if w.Code != 405 {
		t.Fatalf("expected 405, got %d", w.Code)
	}
	if got := w.Header().Get("Allow"); got != "GET, HEAD" {
		t.Fatalf("expected Allow: GET, HEAD, got %q", got)
	}
}

func TestMiddlewareAllowHeader(t *testing.T) {
	r := chi.NewRouter()
	r.Use(middleware.SetAllowHeader)
	r.Get("/users", func(w http.ResponseWriter, r *http.Request) {})
	r.Post("/users", func(w http.ResponseWriter, r *http.Request) {})

	req := httptest.NewRequest(http.MethodPut, "/users", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)

	if got := w.Header().Get("Allow"); got != "GET, POST" {
		t.Fatalf("expected Allow: GET, POST, got %q", got)
	}

	req2 := httptest.NewRequest(http.MethodGet, "/users", nil)
	w2 := httptest.NewRecorder()
	r.ServeHTTP(w2, req2)
	if got := w2.Header().Get("Allow"); got != "" {
		t.Fatalf("expected no Allow header on 2xx, got %q", got)
	}
}

func TestCORS(t *testing.T) {
	r := chi.NewRouter()
	r.EnableCORS()
	r.Get("/api/users", func(w http.ResponseWriter, r *http.Request) {})
	r.Post("/api/users", func(w http.ResponseWriter, r *http.Request) {})

	// normal request
	req := httptest.NewRequest(http.MethodGet, "/api/users", nil)
	w := httptest.NewRecorder()
	r.ServeHTTP(w, req)
	if got := w.Header().Get("Access-Control-Allow-Origin"); got != "*" {
		t.Fatalf("expected wildcard origin, got %q", got)
	}

	// preflight request
	req2 := httptest.NewRequest(http.MethodOptions, "/api/users", nil)
	req2.Header.Set("Access-Control-Request-Method", "POST")
	req2.Header.Set("Origin", "http://example.com")
	w2 := httptest.NewRecorder()
	r.ServeHTTP(w2, req2)

	if w2.Code != 204 {
		t.Fatalf("expected 204, got %d", w2.Code)
	}
	methods := w2.Header().Get("Access-Control-Allow-Methods")
	if methods == "" {
		t.Fatalf("expected non-empty Allow-Methods")
	}
	t.Logf("methods: %s", methods)
	if w2.Header().Get("Access-Control-Allow-Headers") == "" {
		t.Fatalf("expected non-empty Allow-Headers")
	}
	if w2.Header().Get("Access-Control-Max-Age") == "" {
		t.Fatalf("expected non-empty Max-Age")
	}

	// method not allowed
	req3 := httptest.NewRequest(http.MethodPut, "/api/users", nil)
	w3 := httptest.NewRecorder()
	r.ServeHTTP(w3, req3)
	if w3.Code != 405 {
		t.Fatalf("expected 405, got %d", w3.Code)
	}
	if got := w3.Header().Get("Allow"); got == "" {
		t.Fatalf("expected non-empty Allow header on 405")
	} else {
		t.Logf("allow: %s", got)
	}
}
EOF
